1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string } & Record<string, unknown>;
10	
11	type QuoteStep = { op: "quote"; items: Array<Item> };
12	
13	type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Array<QuoteStep>;
16	};
17	
18	type QuoteResult = { premium: number };
19	
20	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
21	
22	const quoteStep = (step: QuoteStep): QuoteResult => {
23	  const policyBase = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
24	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
25	  return { premium: Math.ceil(policyBase + firstInsurance + PROCESSING_FEE) };
26	};
27	
28	export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
29	  return { results: scenario.steps.map(quoteStep) };
30	};
